package com.parfyonoff.webscraper.file.writer.structuredwriter;import com.fasterxml.jackson.core.exc.StreamWriteException;import com.fasterxml.jackson.core.type.TypeReference;import com.fasterxml.jackson.databind.DatabindException;import com.fasterxml.jackson.databind.ObjectMapper;import com.fasterxml.jackson.databind.ObjectWriter;import com.parfyonoff.webscraper.aggregation.AggregatedData;import com.parfyonoff.webscraper.file.FileAccessRegistry;import com.parfyonoff.webscraper.file.writer.WriterException;import java.io.File;import java.io.IOException;import java.util.ArrayList;import java.util.List;import java.util.concurrent.locks.ReentrantLock;public class JsonWriter implements StructuredWriter {    private final static ObjectMapper objectMapper = new ObjectMapper();    private final static ObjectWriter objectWriter = objectMapper.writerWithDefaultPrettyPrinter();    @Override    public void write(File file, AggregatedData aggregatedData) {        if (!file.getAbsolutePath().endsWith(".json")) {            throw new WriterException("Not a json file");        }        ReentrantLock fileLock = FileAccessRegistry.getFileLockFromRegistry(file);        fileLock.lock();        try {            try {                objectWriter.writeValue(file, List.of(aggregatedData));            } catch (StreamWriteException exc) {                throw new WriterException("Can't write data to json file: " + exc.getMessage());            } catch (DatabindException exc) {                throw new WriterException("Can't bind data: " + exc.getMessage());            } catch (IOException exc) {                throw new WriterException("Unexpected IO exception while writing to json file: " + exc.getMessage());            }        } finally {            fileLock.unlock();        }    }    @Override    public void append(File file, AggregatedData aggregatedData) {        if (!file.getAbsolutePath().endsWith(".json")) {            throw new WriterException("Not a json file");        }        ReentrantLock fileLock = FileAccessRegistry.getFileLockFromRegistry(file);        fileLock.lock();        try {            try {                List<AggregatedData> aggregatedDataList;                if (!file.exists()) {                    boolean created;                    try {                        created = file.createNewFile();                    } catch (IOException exc) {                        throw new WriterException("Unexpected IO exception while creating json file: " + exc.getMessage());                    }                    if (!created) {                        throw new WriterException("Cannot create file " + file.getAbsolutePath());                    }                }                if (file.length() == 0) {                    objectWriter.writeValue(file, new ArrayList<>());                }                aggregatedDataList = objectMapper.readValue(file, new TypeReference<>() {                });                aggregatedDataList.add(aggregatedData);                objectWriter.writeValue(file, aggregatedDataList);            } catch (StreamWriteException exc) {                throw new WriterException("Can't append data to json file: " + exc.getMessage());            } catch (DatabindException exc) {                throw new WriterException("Can't bind data: " + exc.getMessage());            } catch (IOException exc) {                throw new WriterException("Unexpected IO exception while writing to json file: " + exc.getMessage());            }        } finally {            fileLock.unlock();        }    }}